var e=[{id:`L2_1`,type:`dialog`,speaker:null,text:{KOREA:`오즈를 놓쳤어…… 우리 힘으로는 못 잡아…….`,JPN:`オズを逃した……私たちの力では捕まえられない……`,ENG:`We lost OZ... We can’t catch them on our own...`,TWN:`沒抓到奧茲國……光憑我們根本沒辦法……`},stage:{bg:`BASEMENT`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:null,text:{KOREA:`그, 그럼 우리 벌받는 거야?`,JPN:`じゃ、じゃあ、私たちお仕置きされる？`,ENG:`Th-then... Are we getting punished?`,TWN:`那…我們會被懲罰嗎？`},stage:{bg:`BASEMENT`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:null,text:{KOREA:`벌받고 싶지 않아. 다시 오즈를 붙잡자.`,JPN:`お仕置きされたくない。もう一回オズを捕まえよう。`,ENG:`I don’t want to get punished. Let’s capture OZ.`,TWN:`我不想受罰，再去抓她們吧。`},stage:{bg:`BASEMENT`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:null,text:{KOREA:`헤론…… 헤론 님이 안 계셔.`,JPN:`ヘロン……ヘロン様がいない。`,ENG:`Madam... Madam Heron isn’t here.`,TWN:`可是……海倫夫人不在。`},stage:{bg:`BASEMENT`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:null,text:{KOREA:`헤론 님이 가시면 우린 악몽을 꾸게 될 거야…….`,JPN:`ヘロン様がいないと、私たちは悪夢を見ちゃう……`,ENG:`Without Madam Heron, we’ll have nightmares again...`,TWN:`海倫夫人走掉的話我們會做惡夢的……`},stage:{bg:`BASEMENT`,slots:{L:null,C:null,R:null}}},{id:`L7_1`,type:`dialog`,speaker:null,text:{KOREA:`악몽은 무서워.`,JPN:`悪夢は怖い。`,ENG:`Nightmares are scary.`,TWN:`惡夢好可怕。`},stage:{bg:`BASEMENT`,slots:{L:null,C:null,R:null}}},{id:`L8_1`,type:`dialog`,speaker:null,text:{KOREA:`잠들고 싶지 않아. 악몽 싫어. 무서워. 살려줘…….`,JPN:`眠りたくない。悪夢イヤ。怖い。助けて……`,ENG:`I don’t want to sleep. No more nightmares... I’m scared... Help me...`,TWN:`我不想睡覺，我討厭惡夢，我好怕，救我……`},stage:{bg:`BASEMENT`,slots:{L:null,C:null,R:null}}},{id:`L9_1`,type:`dialog`,speaker:`RUNNER_OZ_NULL_NULL`,text:{KOREA:`……어쩌지. 이 많은 애들을 다 짊어지고 갈 수도 없고.`,JPN:`……どうしよう。この大人数をおんぶして行くわけにもいかないし。`,ENG:`What do we do? We can’t carry all the kids with us.`,TWN:`……怎麼辦？人這麼多，又不可能全都用揹的。`},stage:{bg:`BASEMENT`,slots:{L:null,C:{char_id:`RUNNER_OZ_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L10_1`,type:`dialog`,speaker:`NIGHTMARE_DREAM_NULL_NULL`,text:{KOREA:`도로시. 내가 해결할 수 있어.`,JPN:`ドロシー。私がなんとかするよ。`,ENG:`Dorothy. Leave this to me.`,TWN:`桃樂絲，我有辦法。`},stage:{bg:`BASEMENT`,slots:{L:null,C:{char_id:`NIGHTMARE_DREAM_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L11_1`,type:`dialog`,speaker:`NEWCOMER_NPC_DREAM_NULL`,text:{KOREA:`그 몸으로 뭘 또 어쩌려고 그래!`,JPN:`その体でまた何する気なんだよ！`,ENG:`What are you gonna do in this state?`,TWN:`你又想做什麼！`},stage:{bg:`BASEMENT`,slots:{L:null,C:{char_id:`NEWCOMER_NPC_DREAM_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`NIGHTMARE_DREAM_NULL_NULL`,text:{KOREA:`너도 알잖아. 내가 뭘 할지.`,JPN:`わかるでしょう？　私が何をしようとしてるのか。`,ENG:`You already know what I’m going to do.`,TWN:`你也知道我想做什麼吧？`},stage:{bg:`BASEMENT`,slots:{L:null,C:{char_id:`NIGHTMARE_DREAM_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`NEWCOMER_NPC_DREAM_NULL`,text:{KOREA:`하지만 또 정신을 잃게 되면…… 그보다 이 많은 애들을 무슨 수로 다…….`,JPN:`でもまた気を失っちゃうと……それよりこの大人数を全部どうやって……`,ENG:`But if you lose consciousness again... More importantly, is it even possible with all these kids...?`,TWN:`但是萬一你又暈過去……而且這麼多人，你是要怎麼……`},stage:{bg:`BASEMENT`,slots:{L:null,C:{char_id:`NEWCOMER_NPC_DREAM_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`NIGHTMARE_DREAM_NULL_NULL`,text:{KOREA:`글린다.`,JPN:`グリンダ。`,ENG:`Glinda.`,TWN:`格琳達。`},stage:{bg:`BASEMENT`,slots:{L:null,C:{char_id:`NIGHTMARE_DREAM_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`NIGHTMARE_DREAM_NULL_NULL`,text:{KOREA:`이건…… 내가 꼭 해야만 하는 일이야.`,JPN:`これは……私がやらないといけないことなの。`,ENG:`This is... something that I must do.`,TWN:`這是……我必須要做的事。`},stage:{bg:`BASEMENT`,slots:{L:null,C:{char_id:`NIGHTMARE_DREAM_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`NEWCOMER_NPC_DREAM_NULL`,text:{KOREA:`루루…….`,JPN:`ルル……`,ENG:`Lulu...`,TWN:`露露……`},stage:{bg:`BASEMENT`,slots:{L:null,C:{char_id:`NEWCOMER_NPC_DREAM_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`NIGHTMARE_DREAM_NULL_NULL`,text:{KOREA:`잠시만 기다려.`,JPN:`ちょっと待ってて。`,ENG:`Wait for me.`,TWN:`等我一下。`},stage:{bg:`BASEMENT`,slots:{L:null,C:{char_id:`NIGHTMARE_DREAM_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L23_1`,type:`dialog`,speaker:`RUNNER_OZ_NULL_NULL`,text:{KOREA:`앗. 애들이…….`,JPN:`あっ。みんなが……`,ENG:`Huh? The kids...`,TWN:`他們……`},stage:{bg:`BASEMENT`,slots:{L:null,C:{char_id:`RUNNER_OZ_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L25_1`,type:`dialog`,speaker:null,text:{KOREA:`하음…… 갑자기…… 졸려…….`,JPN:`ふわぁ……急に……眠い……`,ENG:`*Yawn...* I’m so... tired...`,TWN:`呼哈……突然……好睏……`},stage:{bg:`BASEMENT`,slots:{L:null,C:{char_id:`RUNNER_OZ_NULL_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};